// // This module decrements the 4-bit counter value on each positive edge of the clock signal clk when the enable signal en is high. When the reset signal rst_n is low, the counter resets to zero.
module counter_with_enable(
    input clk,
    input rst_n,
    input en,
    output reg [3:0] count
);
    always @(posedge clk or negedge rst_n) begin
        if (~rst_n) begin
            count <= 4'b0000;
        end else if (en) begin
            count <= count + 1;
        end
    end
endmodule
